export const ICON_NAMES = Object.keys(ICONS);

export function Icon({ name, size = 40, bare = false, style }) {
  const ic = ICONS[name];
  if (!ic) return null;
  const html = (bare ? '' : ic.bg) + ic.content;
  return (
    <svg width={size} height={size} viewBox="-28 -28 56 56" fill="none"
      xmlns="http://www.w3.org/2000/svg"
      style={{ display: 'inline-block', verticalAlign: 'middle', ...style }}
      dangerouslySetInnerHTML={{ __html: html }} />
  );
}
